/**
 * v3.28b Patch 1 — Intro slide module library.
 *
 * 10 textless module slide background designs (1920x1080 SVG each), bundled
 * as base64 data URLs. Each entry includes the metadata needed to overlay
 * the editable title:
 *   - id: stable kebab-case identifier (used by editor saved projects)
 *   - name: original module name (used by editor search)
 *   - displayDefault: pre-broken 2-line title default for this module
 *   - titleY: Y coordinate on the 1920x1080 slide where title baseline area sits
 *   - isLight: true if slide background is light (AI slide) → title text color = #002B54
 *   - url: SVG data URL
 *
 * Saved projects store the module's id (not the SVG). The renderer + editor
 * read this library at boot.
 */

export interface IntroModule {
  id: string;
  name: string;
  displayDefault: string;   // includes \n for 2-line layouts
  titleY: number;           // pixel Y on a 1920x1080 slide
  isLight: boolean;
  url: string;
}

export const INTRO_MODULES: IntroModule[] = [
  { id: "compensation_management", name: 'Compensation Management', displayDefault: "Compensation\nManagement", titleY: 548, isLight: false, url: "data:image/svg+xml;base64," },
  { id: "core_hr", name: 'Core HR', displayDefault: "Core HR", titleY: 618, isLight: false, url: "data:image/svg+xml;base64," },
  { id: "darwinbox_ai_journey_so_far", name: 'Darwinbox AI Journey So Far', displayDefault: "Darwinbox AI\nJourney So Far", titleY: 535, isLight: true, url: "data:image/svg+xml;base64," },
  { id: "employee_experience", name: 'Employee Experience', displayDefault: "Employee\nExperience", titleY: 594, isLight: false, url: "data:image/svg+xml;base64," },
  { id: "extensibility_suite", name: 'Extensibility Suite', displayDefault: "Extensibility Suite", titleY: 600, isLight: false, url: "data:image/svg+xml;base64," },
  { id: "global_benefits_management", name: 'Global Benefits Management', displayDefault: "Global Benefits\nManagement", titleY: 577, isLight: false, url: "data:image/svg+xml;base64," },
  { id: "global_payroll", name: 'Global Payroll', displayDefault: "Global Payroll", titleY: 620, isLight: false, url: "data:image/svg+xml;base64," },
  { id: "hr_service_management", name: 'HR Service Management', displayDefault: "HR Service\nManagement", titleY: 556, isLight: false, url: "data:image/svg+xml;base64," },
  { id: "pre_hire_talent_management_recruitment", name: 'Pre-Hire Talent Management Recruitment', displayDefault: "Pre-Hire Talent\nManagement Recruitment", titleY: 569, isLight: false, url: "data:image/svg+xml;base64," },
  { id: "workforce_management", name: 'Workforce Management', displayDefault: "Workforce\nManagement", titleY: 565, isLight: false, url: "data:image/svg+xml;base64," },
];

/** Lookup a module by id. Returns null if not found. */
export function getIntroModule(id: string | null | undefined): IntroModule | null {
  if (!id) return null;
  return INTRO_MODULES.find(m => m.id === id) || null;
}

/** Default module id when none is set. */
export const DEFAULT_INTRO_MODULE_ID = 'global_payroll';
